{
  "title": "टाइमस्टैम्प सटीकता",
  "group": "तारीख/समय",
  "options": [
    { "text": "2024-01-08 13:30:00+00" },
    { "text": "2024-01-08 13:30:00.123456+00" },
    { "text": "2024-01-08 13:30:00.123456789+00" },
    { "text": "2024-01-08 13:30:00.1234567" }
  ],
  "questionProse": [
    "पोस्टग्रेस में अधिकतम `time` सटीकता को पार करने वाला सबसे छोटा `timestamp` लीटरल कौन-सा है?"
  ],
  "explanationProse": [
    "पोस्टग्रेस के टाइमस्टैम्प में माइक्रोसेकंड (6 दशमलव स्थान) सटीकता होती है।\n\n    - अधिकतम: `.123456` (6 अंक)\n    - नैनोसेकंड (9 अंक) समर्थित सटीकता तक गोल कर दिए जाते हैं या काट दिए जाते हैं\n    - समय क्षेत्र अंतर (timestamptz) के लिए स्वीकृत हैं, लेकिन आवश्यक नहीं हैं\n\n    **अक्सर भूले जाने वाला टिप्स:** कुछ भाषाओं/फ्रेमवर्क नैनोसेकंड सटीकता भेजते हैं, लेकिन पोस्टग्रेस टाइमस्टैम्प माइक्रोसेकंड सटीकता में संग्रहीत करता है।"
  ]
}
